    private static final int SOCKET_TIMEOUT_MS = 10000;
    private static final int MAX_RESPONSE_SIZE_BYTES = 10 * 1024 * 1024; // 10MB
    private static final int MAX_REDIRECTIONS = 10;
    private static final String DEFAULT_USER_AGENT = "Mozilla/5.0 (compatible; UrlService/1.0)";

    /**
     * Fetches content from the specified URL.
     *
     * @param userUrl the URL to fetch content from
     * @return the response body as a String
     * @throws IllegalArgumentException if the URL is invalid or uses unsupported protocol
     * @throws IOException              if an I/O error occurs during the request
     * @throws URISyntaxException       if the URL syntax is incorrect
     */
    public String fetchUrlContent(String userUrl) throws IOException, URISyntaxException {
        validateUrl(userUrl);

        URI uri = new URI(userUrl);
        String scheme = uri.getScheme().toLowerCase();

        if (!"http".equals(scheme) && !"https".equals(scheme)) {
            throw new IllegalArgumentException("Only HTTP and HTTPS protocols are supported");
        }

        RequestConfig requestConfig = buildRequestConfig();

        try (CloseableHttpClient httpClient = HttpClients.custom()
                .setDefaultRequestConfig(requestConfig)
                .build()) {

            HttpGet httpGet = new HttpGet(uri);
            httpGet.setHeader("User-Agent", DEFAULT_USER_AGENT);

            try (CloseableHttpResponse response = httpClient.execute(httpGet)) {
                return processResponse(response);
            }
        }
    }

    /**
     * Validates the input URL.
     *
     * @param url the URL to validate
     * @throws IllegalArgumentException if the URL is null, empty, or invalid
     */
    private void validateUrl(String url) {
        if (url == null || url.trim().isEmpty()) {
            throw new IllegalArgumentException("URL cannot be null or empty");
        }

        String trimmedUrl = url.trim();

        // Check for basic URL format
        if (!trimmedUrl.startsWith("http://") && !trimmedUrl.startsWith("https://")) {
            throw new IllegalArgumentException("URL must start with http:// or https://");
        }

        // Validate URL syntax
        try {
            URI uri = new URI(trimmedUrl);
            if (uri.getHost() == null || uri.getHost().isEmpty()) {
                throw new IllegalArgumentException("URL must contain a valid host");
            }
        } catch (URISyntaxException e) {
            throw new IllegalArgumentException("Invalid URL format: " + e.getMessage());
        }
    }

    /**
     * Builds the request configuration with timeouts.
     *
     * @return the RequestConfig object
     */
    private RequestConfig buildRequestConfig() {
        return RequestConfig.custom()
                .setConnectTimeout(CONNECT_TIMEOUT_MS)
                .setSocketTimeout(SOCKET_TIMEOUT_MS)
                .setMaxRedirects(MAX_REDIRECTIONS)
                .setRelativeRedirectsAllowed(true)
                .setCircularRedirectsAllowed(false)
                .build();
    }

    /**
     * Processes the HTTP response and returns the content as a string.
     *
     * @param response the HTTP response
     * @return the response body as a string
     * @throws IOException if an I/O error occurs while reading the response
     */
    private String processResponse(CloseableHttpResponse response) throws IOException {
        int statusCode = response.getStatusLine().getStatusCode();

        if (statusCode < 200 || statusCode >= 300) {
            throw new IOException("HTTP request failed with status code: " + statusCode);
        }

        HttpEntity entity = response.getEntity();

        if (entity == null) {
            return "";
        }

        // Limit response size to prevent memory issues
        long contentLength = entity.getContentLength();
        if (contentLength > MAX_RESPONSE_SIZE_BYTES) {
            throw new IOException("Response content exceeds maximum allowed size of " 
                    + MAX_RESPONSE_SIZE_BYTES + " bytes");
        }

        return EntityUtils.toString(entity, StandardCharsets.UTF_8);
    }
}
